// tools/aequorin/index.tsx — App orchestrator for the Aequorin Ca²⁺
// Calibration tool. This file is the esbuild entry point (bundles to
// tools/aequorin/index.js) and only holds state wiring — chart rendering,
// step panels, sidebar controls, stats-panel, reports, and pure helpers
// live in sibling modules under tools/aequorin/.

import { usePlotToolState } from "../_shell/usePlotToolState";
import { PlotToolShell } from "../_shell/PlotToolShell";
import {
  DEFAULT_KR,
  DEFAULT_KTR,
  DEFAULT_KD,
  DEFAULT_HILL_N,
  calibrate,
  calibrateHill,
  calibrateGeneralized,
  computeAutoYRange,
  detectConditions,
} from "./helpers";
import type { CalibrationFormula } from "./helpers";
import { UploadStep, ConfigureStep } from "./steps";
import { PlotControls } from "./controls";
import { PlotPanel, SampleSelectionOverlay } from "./plot-area";

const { useState, useMemo, useCallback, useRef } = React;

const VIS_INIT_AEQUORIN = {
  xStart: 10,
  xEnd: 800,
  yMin: 0.1,
  yMax: 1.4,
  // When true, the y-axis auto-rescales to the visible x-window. Any manual
  // edit of yMin / yMax flips this off so the user's range sticks.
  autoYRange: true,
  faceted: false,
  plotTitle: "",
  plotSubtitle: "",
  smoothWidth: 3,
  plotBg: "#ffffff",
  showGrid: false,
  lineWidth: 2,
  ribbonOpacity: 0.3,
  gridColor: "#e0e0e0",
  timeStep: 1,
  baseUnit: "s",
  displayUnit: "s",
  showInset: false,
  insetFillOpacity: 0.7,
  insetBarWidth: 70,
  insetBarGap: 0,
  insetYMinCustom: "",
  insetYMaxCustom: "",
  insetW: 400,
  insetH: 200,
  insetErrorType: "none",
  insetShowBarOutline: false,
  insetBarOutlineColor: "#333333",
  insetBarStrokeWidth: 1,
  insetShowGrid: false,
  insetGridColor: "#e0e0e0",
  insetErrorStrokeWidth: 0.8,
  insetXFontSize: 7,
  insetYFontSize: 7,
  insetXLabelAngle: -45,
  showColumnOverlay: false,
  insetShowPoints: false,
  insetPointSize: 3,
  insetPointColor: "#333333",
  // Discrete-palette key driving the per-condition colour seed. Default
  // "okabe-ito" is byte-identical to PALETTE so existing behaviour is
  // preserved exactly. Conditions[].color is local state seeded from this
  // palette via detectConditions; picking a new palette in the sidebar
  // dropdown overwrites every condition's colour.
  discretePalette: "okabe-ito",
};

/* ── Main App (orchestrator) ───────────────────────────────────────────────── */

function App() {
  const shell = usePlotToolState("aequorin", VIS_INIT_AEQUORIN);
  const {
    step,
    setStep,
    fileName,
    setFileName,
    sepOverride,
    setSepOverride,
    setCommaFixed,
    setCommaFixCount,
    setInjectionWarning,
    vis,
    updVis,
  } = shell;

  // Aequorin uses a dual-variant banner — "⚠️"-prefixed strings render as a
  // yellow warning (e.g. partial-parse notices), anything else as a red
  // error. The shared `ParseErrorBanner` driven by `shell.parseError` only
  // renders the red variant, so we keep our own local state and render a
  // custom banner as PlotToolShell children.
  //
  // **Do not route errors through `shell.setParseError` for this tool** —
  // they'd show up in a second, un-styled banner above this one. The
  // distinct name (`parseMessage`, not `parseError`) is the guardrail: any
  // future edit that reaches for the shell's parseError API will produce a
  // linter "unused import" rather than silently double-rendering.
  const [parseMessage, setParseMessage] = useState<string | null>(null);

  const [rawText, setRawText] = useState<any>(null);
  const [formula, setFormula] = useState<CalibrationFormula>("none");
  const [Kr, setKr] = useState(DEFAULT_KR);
  const [Ktr, setKtr] = useState(DEFAULT_KTR);
  const [Kd, setKd] = useState(DEFAULT_KD);
  const [hillN, setHillN] = useState(DEFAULT_HILL_N);
  const [conditions, setConditions] = useState<any[]>([]);
  const [poolReplicates, setPoolReplicates] = useState(true);
  const [columnEnabled, setColumnEnabled] = useState<any>({});

  const parsed = useMemo(() => (rawText ? parseData(rawText) : null), [rawText]);
  const calData = useMemo(() => {
    if (!parsed) return null;
    if (formula === "none") return parsed.data;
    if (formula === "hill") return calibrateHill(parsed.headers, parsed.data, Kd);
    if (formula === "generalized")
      return calibrateGeneralized(parsed.headers, parsed.data, Kr, Ktr, hillN);
    return calibrate(parsed.headers, parsed.data, Kr, Ktr);
  }, [parsed, formula, Kr, Ktr, Kd, hillN]);
  // Signature of only the numerical inputs from `conditions` — i.e. which
  // column indices belong to each condition. Editing a condition's label,
  // color, or enabled flag doesn't change this string, so the heavy
  // per-timepoint and per-replicate loops below are cached across those
  // edits. Renames in particular become cheap: each keystroke on the label
  // input only re-runs the light metadata merge, not the numerics.
  const conditionsNumericKey = conditions
    .map((c: any) => `${c.prefix}:${(c.activeColIndices || c.colIndices).join(",")}`)
    .join("|");

  // Heavy pass: per-timepoint mean + sd per condition. Keyed on the numeric
  // signature so label/color edits skip it entirely.
  const numericStatsByPrefix = useMemo(() => {
    if (!calData || !parsed || conditions.length === 0) return {} as Record<string, any>;
    const nRows = calData.length;
    const out: Record<string, any> = {};
    for (const cond of conditions) {
      const idxs = cond.activeColIndices || cond.colIndices;
      const means: any[] = [];
      const sds: any[] = [];
      for (let r = 0; r < nRows; r++) {
        const vals = idxs.map((i: any) => calData[r][i]).filter((v: any) => v != null);
        if (vals.length === 0) {
          means.push(null);
          sds.push(null);
          continue;
        }
        const m = vals.reduce((a: any, b: any) => a + b, 0) / vals.length;
        means.push(m);
        sds.push(
          vals.length < 2
            ? 0
            : Math.sqrt(vals.reduce((a: any, v: any) => a + (v - m) ** 2, 0) / (vals.length - 1))
        );
      }
      out[cond.prefix] = { means, sds };
    }
    return out;
    // `conditions` is intentionally read via the numeric-signature key so
    // label/color edits don't invalidate this cache.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [calData, parsed, conditionsNumericKey]);

  // Cheap pass: merge the per-condition metadata (label, color, enabled, …)
  // with the cached numerics. Runs on every `conditions` change, but does
  // not touch `calData` rows.
  const stats = useMemo(
    () =>
      conditions.map((cond: any) => ({
        ...cond,
        ...(numericStatsByPrefix[cond.prefix] || { means: [], sds: [] }),
      })),
    [conditions, numericStatsByPrefix]
  );

  // Per-replicate sums for the inset barplot — computed from calData directly so SD/SEM
  // reflect variability across biological replicates, not across time points.
  // Split the same way as above: heavy loops are keyed on the numeric
  // signature + x-window, the cheap merge attaches the current label.
  const replicateSumsByPrefix = useMemo(() => {
    if (!calData || conditions.length === 0) return {};
    const r0 = Math.max(0, Math.floor(vis.xStart));
    const r1 = Math.min(calData.length - 1, Math.ceil(vis.xEnd));
    const out: Record<string, any> = {};
    for (const cond of conditions) {
      const repSums = (cond.activeColIndices || cond.colIndices).map((ci: any) => {
        const vals: any[] = [];
        for (let r = r0; r <= r1; r++) {
          const v = calData[r] ? calData[r][ci] : null;
          if (v != null) vals.push(v);
        }
        const rawSum = vals.reduce((a: any, b: any) => a + b, 0);
        const minVal = vals.length > 0 ? Math.min(...vals) : 0;
        const corrSum = rawSum - vals.length * minVal;
        return { rawSum, corrSum };
      });
      out[cond.prefix] = repSums;
    }
    return out;
    // Same numeric-signature trick as numericStatsByPrefix above —
    // `conditions` is read via conditionsNumericKey to avoid recomputing on
    // label/color edits.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [calData, conditionsNumericKey, vis.xStart, vis.xEnd]);

  const replicateSums = useMemo(
    () =>
      stats.map((s: any) => ({
        prefix: s.prefix,
        label: s.label,
        repSums: replicateSumsByPrefix[s.prefix] || [],
      })),
    [stats, replicateSumsByPrefix]
  );

  // Effective y-range for the chart. When `autoYRange` is on, recompute
  // every render directly from calData — that's what the chart consumes,
  // so it never paints a frame with stale persisted vis.yMin / vis.yMax
  // (the prior useLayoutEffect-based fix still left a one-frame glitch
  // on the first paint of the plot step because the chart had already
  // received the stale vis values via props by the time the effect's
  // re-render landed).
  //
  // `vis.yMin / vis.yMax` are kept in sync via the effect below, so
  // PrefsPanel save / load round-trips and the manual-override path
  // (autoYRange=false) keep working unchanged.
  const effYRange = useMemo(() => {
    if (!vis.autoYRange) return { yMin: vis.yMin, yMax: vis.yMax };
    const range = computeAutoYRange(calData, vis.xStart, vis.xEnd);
    return range ?? { yMin: vis.yMin, yMax: vis.yMax };
  }, [vis.autoYRange, vis.yMin, vis.yMax, vis.xStart, vis.xEnd, calData]);

  // Mirror the auto-computed range back into `vis` so a later toggle of
  // autoYRange → false snapshots the current visual range, the
  // PrefsPanel file save captures it, and the controls' Y-min / Y-max
  // inputs reflect what's on screen. Plain useEffect (not layout): the
  // chart already renders from `effYRange` so there's no paint glitch
  // to race; this is purely a state-mirror.
  React.useEffect(() => {
    if (!vis.autoYRange) return;
    if (effYRange.yMin === vis.yMin && effYRange.yMax === vis.yMax) return;
    updVis({ yMin: effYRange.yMin, yMax: effYRange.yMax });
  }, [effYRange, vis.autoYRange, vis.yMin, vis.yMax, updVis]);

  const csvText = useMemo(() => {
    if (!calData || !parsed) return "";
    const enabledIdx = parsed.headers
      .map((_: any, i: number) => i)
      .filter((i: any) => columnEnabled[i] !== false);
    const rows = [enabledIdx.map((i: any) => parsed.headers[i]).join(",")];
    calData.forEach((r: any) =>
      rows.push(enabledIdx.map((i: any) => (r[i] != null ? r[i] : "")).join(","))
    );
    return rows.join("\n");
  }, [calData, parsed, columnEnabled]);

  // Per-column rep numbers and name counts (for the column grouping UI)
  const colInfo = useMemo(() => {
    if (!parsed) return [];
    const nameOcc: Record<string, number> = {};
    const nameCount: Record<string, number> = {};
    parsed.headers.forEach((h: any) => {
      nameCount[h] = (nameCount[h] || 0) + 1;
    });
    return parsed.headers.map((h: any, i: number) => {
      nameOcc[h] = (nameOcc[h] || 0) + 1;
      return { h, i, rep: nameOcc[h], isDup: nameCount[h] > 1 };
    });
  }, [parsed]);

  const applyGrouping = (pool: any, ce: any, prevConds: any) => {
    const prevMap: Record<string, any> = Object.fromEntries(
      prevConds.map((c: any) => [c.prefix, c])
    );
    // Build conditions from ALL columns, then mark enabled based on columnEnabled
    const allConds = detectConditions(
      parsed!.headers,
      pool,
      null,
      vis.discretePalette || "okabe-ito"
    ).map((c: any) => {
      const activeCols = c.colIndices.filter((ci: any) => ce[ci] !== false);
      const prev = prevMap[c.prefix];
      // If the previous condition had no active columns, its `enabled=false` was
      // forced by the sample selector rather than a user toggle on the control
      // panel — so re-checking a replicate should bring the whole condition back.
      const prevWasForcedOff =
        prev && (prev.activeColIndices ? prev.activeColIndices.length === 0 : false);
      const enabled = activeCols.length > 0 && (prev && !prevWasForcedOff ? prev.enabled : true);
      return {
        ...c,
        activeColIndices: activeCols,
        enabled,
        label: prev?.label ?? c.label,
        color: prev?.color ?? c.color,
      };
    });
    setConditions(allConds);
  };

  const handlePoolChange = (pool: any) => {
    setPoolReplicates(pool);
    applyGrouping(pool, columnEnabled, conditions);
  };
  const handleColumnToggle = (i: any, val: any) => {
    const ce = { ...columnEnabled, [i]: val };
    setColumnEnabled(ce);
    applyGrouping(poolReplicates, ce, conditions);
  };
  const handleConditionsChange = (newConds: any) => {
    const ce = { ...columnEnabled };
    const updated = newConds.map((c: any, idx: number) => {
      const prev = conditions[idx];
      // Only sync columnEnabled for conditions whose enabled state actually changed
      if (prev && c.enabled !== prev.enabled) {
        c.colIndices.forEach((ci: any) => {
          ce[ci] = c.enabled;
        });
        return { ...c, activeColIndices: c.enabled ? c.colIndices : [] };
      }
      return c;
    });
    setConditions(updated);
    setColumnEnabled(ce);
  };

  const plotPanelRef = useRef<any>(null);

  const doParse = useCallback(
    (text: any, sep: any) => {
      const dc = fixDecimalCommas(text, sep);
      setCommaFixed(dc.commaFixed);
      setCommaFixCount(dc.count);
      setRawText(dc.text);
      const { headers, data, injectionWarnings } = parseData(dc.text, sep);
      setInjectionWarning(injectionWarnings);
      if (!headers.length || !data.length) {
        setParseMessage(
          "The file appears to be empty or has no data rows. Please check your file and try again."
        );
        return;
      }
      // Check for single-column files
      if (headers.length === 1) {
        setParseMessage(
          "Only one column detected — this tool expects wide-format data with one column per sample. Check your separator setting or file format."
        );
        return;
      }
      // Check how much of the data is numeric
      const totalCells = data.length * headers.length;
      const numericCells = data.reduce(
        (n: any, row: any) => n + row.filter((v: any) => v != null).length,
        0
      );
      const numericRatio = totalCells > 0 ? numericCells / totalCells : 0;
      if (numericRatio < 0.3) {
        setParseMessage(
          "Less than 30% of values are numeric. This tool expects a numeric matrix (one column per sample, one row per time-point). Your file may be in long format or contain mostly text."
        );
        return;
      }
      // Warn if the file looks like long format (few columns, one text + one numeric pattern)
      const colTypes = headers.map((_: any, ci: number) => {
        const nums = data.filter((r: any) => r[ci] != null).length;
        return nums / data.length > 0.8 ? "num" : "text";
      });
      const numCols = colTypes.filter((t: any) => t === "num").length;
      const textCols = colTypes.filter((t: any) => t === "text").length;
      const warnings: any[] = [];
      if (headers.length <= 3 && textCols >= 1 && numCols >= 1)
        warnings.push(
          "⚠️ This looks like it could be long-format data (few columns, mix of text and numbers). This tool expects wide format — one column per sample, one row per time-point."
        );
      // Detect ragged columns (different number of valid values per column)
      const colLengths = headers.map(
        (_: any, ci: number) => data.filter((r: any) => r[ci] != null).length
      );
      const maxLen = Math.max(...colLengths);
      const minLen = Math.min(...colLengths);
      if (maxLen > 0 && minLen < maxLen) {
        warnings.push(
          `⚠️ Columns have different lengths (${minLen}–${maxLen} numeric values). Some samples may have missing time-points, which can affect mean/SD calculations.`
        );
      }
      setParseMessage(warnings.length > 0 ? warnings.join("\n") : null);
      const ce: Record<string, any> = {};
      headers.forEach((_: any, i: number) => {
        ce[i] = true;
      });
      setColumnEnabled(ce);
      setPoolReplicates(true);
      const detectedConds = detectConditions(
        headers,
        true,
        ce,
        vis.discretePalette || "okabe-ito"
      ).map((c: any) => ({
        ...c,
        enabled: true,
      }));
      setConditions(detectedConds);
      // Reset autoYRange on every fresh parse — manual Y bounds (which set
      // autoYRange=false in the controls) only make sense for the data
      // they were dialled in on. Without this, persisted autoYRange=false
      // + persisted yMin/yMax from a previous session crops the next
      // dataset to the old range on first paint after reload.
      updVis({ xStart: 0, xEnd: data.length, faceted: false, autoYRange: true });
      setStep("configure");
    },
    [setCommaFixed, setCommaFixCount, setInjectionWarning, setStep, updVis, vis.discretePalette]
  );
  const handleFileLoad = useCallback(
    (text: any, name: any) => {
      setFileName(name);
      doParse(text, sepOverride);
    },
    [sepOverride, doParse, setFileName]
  );
  const loadExample = useCallback(() => {
    const text = (window as any).__AEQUORIN_EXAMPLE__;
    if (!text) {
      setParseMessage("Example dataset not loaded. Please try uploading a file instead.");
      return;
    }
    setSepOverride("\t");
    setFileName("rlu_timecourse_example.tsv");
    doParse(text, "\t");
  }, [doParse, setFileName, setSepOverride]);
  const resetAll = () => {
    setRawText(null);
    setFileName("");
    setInjectionWarning(null);
    setStep("upload");
  };

  const downloadCalibrated = () => {
    if (!csvText) return;
    const blob = new Blob([csvText], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${fileBaseName(fileName, "rlu_timecourse")}_calibrated.csv`;
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  };

  const canNavigate = (s: any) => s === "upload" || (!!parsed && s !== "upload");

  return (
    <PlotToolShell
      state={shell}
      toolName="aequorin"
      title="RLU timecourse"
      visInit={VIS_INIT_AEQUORIN}
      steps={["upload", "configure", "plot"]}
      canNavigate={canNavigate}
    >
      {parseMessage && (
        <div
          style={{
            marginBottom: 16,
            padding: "10px 14px",
            borderRadius: 8,
            background: parseMessage.startsWith("⚠️") ? "#fffbeb" : "#fef2f2",
            border: `1px solid ${parseMessage.startsWith("⚠️") ? "#fcd34d" : "#fca5a5"}`,
            display: "flex",
            alignItems: "flex-start",
            gap: 8,
          }}
        >
          {!parseMessage.startsWith("⚠️") && <span style={{ fontSize: 16 }}>🚫</span>}
          <span
            style={{
              fontSize: 12,
              color: parseMessage.startsWith("⚠️") ? "var(--warning-text)" : "var(--danger-text)",
              fontWeight: 600,
              whiteSpace: "pre-line",
            }}
          >
            {parseMessage}
          </span>
        </div>
      )}

      {step === "upload" && (
        <UploadStep
          sepOverride={sepOverride}
          setSepOverride={setSepOverride}
          rawText={rawText}
          doParse={doParse}
          handleFileLoad={handleFileLoad}
          onLoadExample={loadExample}
        />
      )}

      {step === "configure" && parsed && (
        <ConfigureStep
          parsed={parsed}
          formula={formula}
          setFormula={setFormula}
          Kr={Kr}
          setKr={setKr}
          Ktr={Ktr}
          setKtr={setKtr}
          Kd={Kd}
          setKd={setKd}
          hillN={hillN}
          setHillN={setHillN}
          vis={vis}
          updVis={updVis}
          fileName={fileName}
          calData={calData}
          columnEnabled={columnEnabled}
          downloadCalibrated={downloadCalibrated}
        />
      )}

      {step === "plot" && parsed && calData && (
        <div>
          <div style={{ display: "flex", gap: 20, alignItems: "flex-start" }}>
            {/* LEFT: controls panel */}
            <PlotControls
              conditions={conditions}
              setConditions={handleConditionsChange}
              vis={vis}
              updVis={updVis}
              plotPanelRef={plotPanelRef}
              downloadCalibrated={downloadCalibrated}
              resetAll={resetAll}
            />

            {/* RIGHT: chart area */}
            <div
              className="dv-aeq-chart-area"
              style={{ flex: 1, minWidth: 0, position: "relative" }}
            >
              {/* Non-sticky Series (Pool/Individual) + Layout (Combined/Faceted)
                  toggles. On wide chart columns they're absolutely positioned
                  at the top-right so on landing they share a row with the
                  sticky Sample-selection pill, but scroll away normally
                  while Sample selection alone continues to stick. The two
                  groups are separated by a gap and carry tiny captions
                  because they're orthogonal axes: Series is a data-shape
                  decision (how replicates are pooled), Layout is a visual
                  decision (one plot vs. one per condition). Both use the
                  shared --step-active-* slate accent to match the rest of
                  the app chrome — the caption + grouping carries the
                  distinction, not a bespoke hue.

                  All positioning + the responsive collapse live in
                  components.css under `.dv-aeq-toggles-group`. A container
                  query on `.dv-aeq-chart-area` (max-width: 620px) flips
                  this to a right-aligned vertical stack AND drops it back
                  into flow (`position: static`) so the chart below moves
                  downstairs instead of being overlapped. */}
              <div className="dv-aeq-toggles-group">
                <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end" }}>
                  <span
                    style={{
                      fontSize: 9,
                      fontWeight: 700,
                      letterSpacing: "0.04em",
                      textTransform: "uppercase",
                      color: "var(--text-faint)",
                      marginBottom: 2,
                    }}
                  >
                    Series
                  </span>
                  <div
                    role="group"
                    aria-label="Series definition"
                    style={{
                      display: "inline-flex",
                      border: "1px solid var(--step-active-border)",
                      borderRadius: 8,
                      overflow: "hidden",
                      background: "var(--surface)",
                    }}
                  >
                    <button
                      onClick={() => handlePoolChange(true)}
                      aria-pressed={poolReplicates}
                      style={{
                        padding: "6px 14px",
                        fontSize: 12,
                        fontWeight: 600,
                        fontFamily: "inherit",
                        cursor: "pointer",
                        background: poolReplicates ? "var(--step-active-bg)" : "transparent",
                        color: poolReplicates ? "var(--on-accent)" : "var(--text-faint)",
                        border: "none",
                        borderRight: "1px solid var(--step-active-border)",
                      }}
                    >
                      Pool by name
                    </button>
                    <button
                      onClick={() => handlePoolChange(false)}
                      aria-pressed={!poolReplicates}
                      style={{
                        padding: "6px 14px",
                        fontSize: 12,
                        fontWeight: 600,
                        fontFamily: "inherit",
                        cursor: "pointer",
                        background: !poolReplicates ? "var(--step-active-bg)" : "transparent",
                        color: !poolReplicates ? "var(--on-accent)" : "var(--text-faint)",
                        border: "none",
                      }}
                    >
                      Individual
                    </button>
                  </div>
                </div>
                <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end" }}>
                  <span
                    style={{
                      fontSize: 9,
                      fontWeight: 700,
                      letterSpacing: "0.04em",
                      textTransform: "uppercase",
                      color: "var(--text-faint)",
                      marginBottom: 2,
                    }}
                  >
                    Layout
                  </span>
                  <div
                    role="group"
                    aria-label="Plot layout"
                    style={{
                      display: "inline-flex",
                      border: "1px solid var(--step-active-border)",
                      borderRadius: 8,
                      overflow: "hidden",
                      background: "var(--surface)",
                    }}
                  >
                    <button
                      onClick={() => updVis({ faceted: false })}
                      aria-pressed={!vis.faceted}
                      style={{
                        padding: "6px 14px",
                        fontSize: 12,
                        fontWeight: 600,
                        fontFamily: "inherit",
                        cursor: "pointer",
                        background: !vis.faceted ? "var(--step-active-bg)" : "transparent",
                        color: !vis.faceted ? "var(--on-accent)" : "var(--text-faint)",
                        border: "none",
                        borderRight: "1px solid var(--step-active-border)",
                      }}
                    >
                      Combined
                    </button>
                    <button
                      onClick={() => updVis({ faceted: true })}
                      aria-pressed={vis.faceted}
                      style={{
                        padding: "6px 14px",
                        fontSize: 12,
                        fontWeight: 600,
                        fontFamily: "inherit",
                        cursor: "pointer",
                        background: vis.faceted ? "var(--step-active-bg)" : "transparent",
                        color: vis.faceted ? "var(--on-accent)" : "var(--text-faint)",
                        border: "none",
                      }}
                    >
                      Faceted
                    </button>
                  </div>
                </div>
              </div>
              {/* Sticky row: Sample selection. `width: fit-content` keeps
                  the wrapper from stretching across the column — otherwise
                  its empty right half (higher zIndex) sits on top of the
                  absolutely-positioned Combined/Faceted toggle and blocks
                  clicks. */}
              <div
                style={{
                  position: "sticky",
                  top: 0,
                  zIndex: 20,
                  marginBottom: 10,
                  display: "flex",
                  alignItems: "flex-start",
                  gap: 12,
                  width: "fit-content",
                }}
              >
                <SampleSelectionOverlay
                  showColumnOverlay={vis.showColumnOverlay}
                  setShowColumnOverlay={(v: any) => updVis({ showColumnOverlay: v })}
                  poolReplicates={poolReplicates}
                  colInfo={colInfo}
                  columnEnabled={columnEnabled}
                  handleColumnToggle={handleColumnToggle}
                  conditions={conditions}
                />
              </div>
              <PlotPanel
                ref={plotPanelRef}
                stats={stats}
                xStart={vis.xStart}
                xEnd={vis.xEnd}
                yMin={effYRange.yMin}
                yMax={effYRange.yMax}
                faceted={vis.faceted}
                title={vis.plotTitle}
                subtitle={vis.plotSubtitle}
                smoothWidth={vis.smoothWidth}
                formula={formula}
                replicateSums={replicateSums}
                fileName={fileName}
                plotBg={vis.plotBg}
                showGrid={vis.showGrid}
                lineWidth={vis.lineWidth}
                ribbonOpacity={vis.ribbonOpacity}
                gridColor={vis.gridColor}
                timeStep={vis.timeStep}
                baseUnit={vis.baseUnit}
                displayUnit={vis.displayUnit}
                showInset={vis.showInset}
                insetFillOpacity={vis.insetFillOpacity}
                insetBarWidth={vis.insetBarWidth}
                insetBarGap={vis.insetBarGap}
                insetYMin={vis.insetYMinCustom !== "" ? Number(vis.insetYMinCustom) : null}
                insetYMax={vis.insetYMaxCustom !== "" ? Number(vis.insetYMaxCustom) : null}
                insetW={vis.insetW}
                insetH={vis.insetH}
                insetErrorType={vis.insetErrorType}
                insetShowBarOutline={vis.insetShowBarOutline}
                insetBarOutlineColor={vis.insetBarOutlineColor}
                insetBarStrokeWidth={vis.insetBarStrokeWidth}
                insetShowGrid={vis.insetShowGrid}
                insetGridColor={vis.insetGridColor}
                insetErrorStrokeWidth={vis.insetErrorStrokeWidth}
                insetXFontSize={vis.insetXFontSize}
                insetYFontSize={vis.insetYFontSize}
                insetXLabelAngle={vis.insetXLabelAngle}
                insetShowPoints={vis.insetShowPoints}
                insetPointSize={vis.insetPointSize}
                insetPointColor={vis.insetPointColor}
              />
            </div>
          </div>
        </div>
      )}
    </PlotToolShell>
  );
}

ReactDOM.createRoot(document.getElementById("root")!).render(
  <ErrorBoundary toolName="RLU timecourse">
    <App />
  </ErrorBoundary>
);
